from flask import Flask, render_template
app = Flask(__name__)
@app.route('/')
def index():
    return render_template('index.html')
@app.route('/user/<path:username>')
def show_user_profile(username):
    return 'User %s' % username
if __name__ == '__main__':
    app.run(debug=True)
